}

// Portable agent-definition document (agent-definition-as-data). Server stores the
// roster only — role → model binding and the owner ($HOME) axis are local, not columns.
// JSON wire: camelCase. Unknown properties are ignored for forward-compat EXCEPT
// any property named "model" anywhere in the JSON tree (root, roles, spawn, nested),
// which is rejected (portable definitions must not carry models).

// Periodically snapshots every internal SQLite db (Backup.SnapshotAll). First pass
// runs shortly after startup, then on the interval. A separate pre-migration
// snapshot is taken inline in Program.cs before MigrationRunner runs.
public sealed partial class BackupService(string dataDir, ILogger<BackupService> logger) : BackgroundService
{
	public static readonly TimeSpan Interval = TimeSpan.FromHours(12);
	public const int RetainSets = 14;

protected override Task HandleRequirementAsync(
		AuthorizationHandlerContext context,
		ScopeRequirement requirement)
	{
		var scopesClaim = context.User.FindFirstValue("scopes");
		if (scopesClaim is not null && HasScope(scopesClaim, requirement.RequiredScope))
			context.Succeed(requirement);

		return Task.CompletedTask;
	}

	static bool HasScope(string scopes, string required)
	{
		if (string.IsNullOrWhiteSpace(scopes))
			return false;
		return scopes
			.Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
			.Any(s => string.Equals(s, required, StringComparison.OrdinalIgnoreCase));
	}

// The baseline quotes a version this scope never reached (> the scope cursor) — almost
	// always a currentVersion carried over from a DIFFERENT board/store. Reason spells out
	// the two version spaces. Caught before any other classification.
	FutureBaseline,

// Overload that also soft-deletes (closes the active row with no new revision) the
	// given keys — used by memory_upsert's `deleted:true`. version 0 = delete the
	// current active row regardless; a non-zero version that no longer matches yields a
	// Stale conflict; deleting a key with no active row is a no-op (idempotent).

// Portable agent-definition store (NOT the deploy node-agent poll/heartbeat pair).
	public const string AgentsRead = "agents:read";
	public const string AgentsWrite = "agents:write";
	public const string AdminProvision = "admin:provision";

// Metadata row for a single named memory store. PK is (ProjectKey, Name). Entries
// live in `data/memory/{ProjectKey}/{Name}.db` (temporal table). v1 is
// project-scoped only; global/workspace scopes are a documented future extension.
// Mirrors LogMeta — explicit creation, no auto-vivify.

// One row the caller could not apply because the store moved under its baseline
// (or a domain guard refused it — then Reason says why). On a Stale conflict,
// ChangedFields names the payload fields of THIS entity that differ between the
// revision the author read and the current one (entity-scoped by construction —
// never other entities' noise), so a retry is informed, not blind.
public sealed record TemporalConflict(
	string Key,
	TemporalConflictKind Kind,
	long BaselineVersion,
	long? ActiveVersion,
	string? Reason = null,
	IReadOnlyList<string>? ChangedFields = null);

